import React, { useState } from 'react';
import Header from '../components/Header';
import Sidebar from '../components/Sidebar';
import Dashboard from './Dashboard';
import EnquiryIndex from './enquiry/index';
import NewEnquiry from './enquiry/NewEnquiry';
import UpdateEnquiry from './enquiry/UpdateEnquiry';
import ProvisionalAdmission from './enquiry/ProvisionalAdmission';
import EmailPage from './email/EmailPage';
import AdmissionPage from './admissions/AdmissionPage';
import StaffManagement from './staff/StaffManagement';
import AnalysisPage from './analysis/AnalysisPage';
import HodAdmissionsPage from './hod/HodAdmissionsPage';
import HodEnquiriesPage from './hod/HodEnquiriesPage';
import { canAccessPage } from '../data/menuData';
import { COLORS, SPACING, SHADOWS } from '../utils/designSystem';

const DashboardLayout = ({ user, onLogout }) => {
  const [activePage, setActivePage] = useState('dashboard');
  const [sidebarOpen, setSidebarOpen] = useState(false);

  // Render the appropriate page based on activePage
  const renderPage = () => {
    // Security: Check if user has access
    if (!canAccessPage(user, activePage)) {
      return <Dashboard user={user} />;
    }

    switch (activePage) {
      case 'dashboard':
        return <Dashboard user={user} />;
      case 'enquiries':
        return <EnquiryIndex />;
      case 'new-enquiry':
        return <NewEnquiry />;
      case 'update-enquiry':
        return <UpdateEnquiry />;
      case 'provisional-admission':
        return <ProvisionalAdmission />;
      case 'email-enquiry':
        return <EmailPage scope="ENQUIRY" />;
      case 'email-admission':
        return <EmailPage scope="ADMISSION" />;
      case 'admissions':
        return <AdmissionPage />;
      case 'hod-admissions':
        return <HodAdmissionsPage />;
      case 'hod-enquiries':
        return <HodEnquiriesPage />;
      case 'analysis':
        return <AnalysisPage user={user} />;
      case 'staff':
        return <StaffManagement currentUser={user} />;
      case 'students':
        return (
          <div>
            <h2 style={{ color: '#1a1a1a', marginBottom: '20px', fontSize: '28px', fontWeight: '700', margin: 0 }}>
              Students
            </h2>
            <p style={{ color: '#666', marginBottom: '30px', fontSize: '14px', fontWeight: '500' }}>
              Manage student information and records
            </p>
            <div style={{ padding: '40px 30px', background: '#f8f9fa', borderRadius: '12px', color: '#1a1a1a', textAlign: 'center', border: '1px solid #e0e0e0' }}>
              <div style={{ fontSize: '48px', marginBottom: '15px' }}>👥</div>
              <h3 style={{ fontSize: '20px', fontWeight: '600', margin: '0 0 10px 0', color: '#1a1a1a' }}>
                Student Management
              </h3>
              <p style={{ margin: 0, opacity: 0.7, fontSize: '14px', color: '#666' }}>
                Coming soon! This feature will allow you to manage student information, records, and enrollment.
              </p>
            </div>
          </div>
        );
      case 'fees':
        return (
          <div>
            <h2 style={{ color: '#1a1a1a', marginBottom: '20px', fontSize: '28px', fontWeight: '700', margin: 0 }}>
              Fees Management
            </h2>
            <p style={{ color: '#666', marginBottom: '30px', fontSize: '14px', fontWeight: '500' }}>
              Track and manage student fees payment
            </p>
            <div style={{ padding: '40px 30px', background: '#f8f9fa', borderRadius: '12px', color: '#1a1a1a', textAlign: 'center', border: '1px solid #e0e0e0' }}>
              <div style={{ fontSize: '48px', marginBottom: '15px' }}>💰</div>
              <h3 style={{ fontSize: '20px', fontWeight: '600', margin: '0 0 10px 0', color: '#1a1a1a' }}>
                Fee Management
              </h3>
              <p style={{ margin: 0, opacity: 0.7, fontSize: '14px', color: '#666' }}>
                Coming soon! Track student fee payments, generate invoices, and manage fee collections.
              </p>
            </div>
          </div>
        );
      case 'courses':
        return (
          <div>
            <h2 style={{ color: '#1a1a1a', marginBottom: '20px', fontSize: '28px', fontWeight: '700', margin: 0 }}>
              Courses
            </h2>
            <p style={{ color: '#666', marginBottom: '30px', fontSize: '14px', fontWeight: '500' }}>
              Manage courses and curriculum
            </p>
            <div style={{ padding: '40px 30px', background: '#f8f9fa', borderRadius: '12px', color: '#1a1a1a', textAlign: 'center', border: '1px solid #e0e0e0' }}>
              <div style={{ fontSize: '48px', marginBottom: '15px' }}>📚</div>
              <h3 style={{ fontSize: '20px', fontWeight: '600', margin: '0 0 10px 0', color: '#1a1a1a' }}>
                Course Management
              </h3>
              <p style={{ margin: 0, opacity: 0.7, fontSize: '14px', color: '#666' }}>
                Coming soon! Create and manage courses, assign faculty, and define curriculum.
              </p>
            </div>
          </div>
        );
      case 'department':
        return (
          <div>
            <h2 style={{ color: '#1a1a1a', marginBottom: '20px', fontSize: '28px', fontWeight: '700', margin: 0 }}>
              Department Management
            </h2>
            <p style={{ color: '#666', marginBottom: '30px', fontSize: '14px', fontWeight: '500' }}>
              Manage your department details and faculty
            </p>
            <div style={{ padding: '40px 30px', background: '#f8f9fa', borderRadius: '12px', color: '#1a1a1a', textAlign: 'center', border: '1px solid #e0e0e0' }}>
              <div style={{ fontSize: '48px', marginBottom: '15px' }}>👨‍💼</div>
              <h3 style={{ fontSize: '20px', fontWeight: '600', margin: '0 0 10px 0', color: '#1a1a1a' }}>
                Department Information
              </h3>
              <p style={{ margin: 0, opacity: 0.7, fontSize: '14px', color: '#666' }}>
                Coming soon! Manage department details, faculty assignments, and departmental operations.
              </p>
            </div>
          </div>
        );
      default:
        return <Dashboard user={user} />;
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: COLORS.backgroundSecondary,
      paddingLeft: sidebarOpen ? '330px' : '50px',
      paddingTop: '100px',
      paddingRight: SPACING['2xl'],
      paddingBottom: SPACING['2xl'],
      transition: 'padding-left 0.35s cubic-bezier(0.4, 0, 0.2, 1)',
      position: 'relative'
    }}>
      {/* Header */}
      <Header user={user} onLogout={onLogout} />

      {/* Sidebar */}
      <Sidebar
        onNavigate={setActivePage}
        currentPage={activePage}
        userRole={user?.role}
        user={user}
        isOpen={sidebarOpen}
        onOpenChange={setSidebarOpen}
      />

      {/* Main Content */}
      <div style={{
        maxWidth: '1400px',
        margin: '0 auto',
        background: COLORS.background,
        borderRadius: '14px',
        boxShadow: SHADOWS.md,
        overflow: 'hidden'
      }}>
        <div style={{
          padding: SPACING['4xl']
        }}>
          {renderPage()}
        </div>
      </div>
    </div>
  );
};

export default DashboardLayout;



